form:Form.form:Scripts:
		function LoadForm()
{
 	val_orden();    
 	ClearGrid();
}
function val_orden() 
{
if (Ctrl('orden1').GetXValue() == "ORG03_UBICACIONES.c_ubicacion" || Ctrl('orden1').GetXValue() == "ORG03_UBICACIONES.d_ubicacion")
 {
 	CtrlEnabled('orden2',true);
 }
else
 {
  CtrlEnabled('orden2',false);
  Ctrl("orden2").SetXValue("");
 } 
}

function ClearGrid()
{
	Ctrl('grdDatosLiq').DelAllRows();
}


function change_parent()
{   
	if(Ctrl('oi_empresa').GetXValue() != '' && Ctrl('e_periodo').GetXValue() != '')
	{
		Ctrl('parent').SetXValue(Ctrl('oi_empresa').GetXValue() + '_' + Ctrl('e_periodo').GetXValue()); 
		FiltroDeLiqui();
	}
	else
	{ 
		Ctrl('parent').SetXValue("");
	}

	ClearGrid();
}     

function ACCEPT()
{
  var result = OnClickValidations();

  if (result) 
  {
  	Ctrl("main").DoEvent("ACCEPT");
  }

  return result; 
} 


function ObtenerLiquidaciones()
{
  var result = "";

  //recorre las liquidaciones
  for (i=0;i<Ctrl('grdDatosLiq').TotalRowsCount();i++)	
	{		
		var ctrl = Ctrl('grdDatosLiq').GetCellControl("oi_liquidacion", i)		
		if (ctrl.GetXValue() != "")
		{
		  if (result != "") 
		  {
		  	result = result + ",";
		  }

			result = result + ctrl.GetXValue();
		}		
	}   
	return result;
}


